1	const PROCESSING_FEE = 5;
2	const SWORD_BASE_PREMIUM = 100;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Step = QuoteStep;
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	
9	const basePremiumFor = (item: Item): number => {
10	  if (item.type === "amulet") return 60;
11	  return SWORD_BASE_PREMIUM;
12	};
13	
14	const quoteStep = (step: QuoteStep): { premium: number } => {
15	  const itemsBase = step.items.reduce((sum, item) => sum + basePremiumFor(item), 0);
16	  return { premium: itemsBase + PROCESSING_FEE };
17	};
18	
19	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
20	  return { results: scenario.steps.map(quoteStep) };
21	};
