41	  it.todo("cursed sword (enchantment 3) → curse surcharge 50%: 100 + 50 + 5 = 155 G");
42	  it.todo("sword with enchantment 5 → high-enchant surcharge 30%: 100 + 30 + 5 = 135 G");
43	  it.todo("sword with enchantment 4 → no high-enchant surcharge: 100 + 5 = 105 G");
44	  it.todo("cursed sword with enchantment 5 → both surcharges: 100 + 50 + 30 + 5 = 185 G");
45	
46	  // Policy-wide modifiers
47	  it.todo("customer with 2 years → loyalty discount 20% applies");
48	  it.todo("customer with 0 years → no loyalty discount");
49	
50	  // Modifier scope on multi-item policies
